import { Panel, PanelSidebarItem } from '@juv/codego-react-ui'
import { Home, Settings } from 'lucide-react'
import { useState } from 'react'

export function ControlledPanel() {
  const [currentPage, setCurrentPage] = useState('home')
  const [collapsed, setCollapsed] = useState(false)

  return (
    <Panel
      sidebar={
        <>
          <PanelSidebarItem
            icon={Home}
            label="Home"
            active={currentPage === 'home'}
            onClick={() => setCurrentPage('home')}
          />
          <PanelSidebarItem
            icon={Settings}
            label="Settings"
            active={currentPage === 'settings'}
            onClick={() => setCurrentPage('settings')}
          />
        </>
      }
      collapsed={collapsed}
      onCollapsedChange={setCollapsed}
      currentPage={currentPage}
      onPageChange={setCurrentPage}
      collapsible
    >
      {currentPage === 'home' && <div>Home Page</div>}
      {currentPage === 'settings' && <div>Settings Page</div>}
    </Panel>
  )
}

import { Panel, PanelSidebarItem } from '@juv/codego-react-ui'
import { useState, useEffect } from 'react'

export function PanelWithStates() {
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)
  const [data, setData] = useState(null)

  useEffect(() => {
    fetchData()
  }, [])

  const fetchData = async () => {
    try {
      setLoading(true)
      const response = await fetch('/api/data')
      if (!response.ok) throw new Error('Failed to fetch')
      setData(await response.json())
      setError(null)
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Unknown error')
    } finally {
      setLoading(false)
    }
  }

  return (
    <Panel
      sidebar={<PanelSidebarItem label="Data" />}
      loading={loading}
      error={error}
      emptyState={<p>No data available</p>}
    >
      {data && <pre>{JSON.stringify(data, null, 2)}</pre>}
    </Panel>
  )
}

import { Panel, PanelSidebarItem, PanelSidebarGroup } from '@juv/codego-react-ui'
import { useState } from 'react'

export function PanelWithGroups() {
  const [expandedGroups, setExpandedGroups] = useState(['Main'])

  const handleGroupToggle = (title: string, expanded: boolean) => {
    setExpandedGroups((prev) =>
      expanded ? [...prev, title] : prev.filter((g) => g !== title)
    )
  }

  return (
    <Panel
      sidebar={
        <>
          <PanelSidebarGroup title="Main">
            <PanelSidebarItem label="Home" />
            <PanelSidebarItem label="Dashboard" />
          </PanelSidebarGroup>
          <PanelSidebarGroup title="Admin">
            <PanelSidebarItem label="Users" />
            <PanelSidebarItem label="Settings" />
          </PanelSidebarGroup>
        </>
      }
      expandedGroups={expandedGroups}
      onGroupToggle={handleGroupToggle}
      showGroupDividers
    >
      <div>Content</div>
    </Panel>
  )
}

import { Panel, PanelSidebarItem } from '@juv/codego-react-ui'
import { useRef } from 'react'

export function PanelWithActions() {
  const panelRef = useRef<HTMLDivElement>(null)
  const [collapsed, setCollapsed] = useState(false)
  const [theme, setTheme] = useState('light')

  const actions = {
    'collapse-sidebar': () => setCollapsed(true),
    'expand-sidebar': () => setCollapsed(false),
    'toggle-sidebar': () => setCollapsed((c) => !c),
    'toggle-theme': () => setTheme((t) => t === 'light' ? 'dark' : 'light'),
    'navigate-home': () => console.log('Navigate to home'),
  }

  return (
    <Panel
      ref={panelRef}
      sidebar={<PanelSidebarItem label="Home" onClick={actions['navigate-home']} />}
      collapsed={collapsed}
      onCollapsedChange={setCollapsed}
      actions={actions}
      meta={{ version: '1.0.0', features: ['ai-actions', 'keyboard-nav'] }}
      keyboardNavigation
      collapsible
    >
      <div>AI-friendly panel with programmatic actions</div>
    </Panel>
  )
}

